typedef struct {
    int starting;
    int no_of_edges;
} Node;

kernel void BFS_1(
    Node* graph_nodes,
    int* graph_edges,
    char* graph_mask,
    char* updating_graph_mask,
    char* graph_visited,
    int* cost,
    int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (graph_mask[tid] == 1) {
            graph_mask[tid] = 0;
            for (int i = graph_nodes[tid].starting; i < (graph_nodes[tid].no_of_edges + graph_nodes[tid].starting); i++) {
                int id = graph_edges[i];
                if (graph_visited[id] == 0) {
                    cost[id] = cost[tid] + 1;
                    updating_graph_mask[id] = 1;
                }
            }
        }
    }
}

kernel void BFS_2(
    char* graph_mask,
    char* updating_graph_mask,
    char* graph_visited,
    char* over,
    int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (updating_graph_mask[tid] == 1) {
            graph_mask[tid] = 1;
            graph_visited[tid] = 1;
            *over = 1;
            updating_graph_mask[tid] = 0;
        }
    }
}
